    tree: Optional[cKDTree],
    pts_um: np.ndarray,
    query_um: np.ndarray,
    radius: float = KNN_RADIUS_UM,
) -> pd.DataFrame:
    N = len(query_um)
    if N == 0 or tree is None:
        return pd.DataFrame({
            "knn_d1": np.full(N, float("nan")),
            "n_neighbors_30um": np.zeros(N, dtype=int),
        })
    valid = np.isfinite(query_um).all(axis=1)
    knn_d1 = np.full(N, float("nan"))
    n_in = np.zeros(N, dtype=int)
    if valid.any():
        # k=2 because query points are themselves in the tree → first neighbour is self
        d, _ = tree.query(query_um[valid], k=min(2, pts_um.shape[0]), workers=1)
        if d.ndim == 1:
            d = d[:, None]
        if d.shape[1] >= 2:
            knn_d1[valid] = d[:, 1]
        counts = tree.query_ball_point(query_um[valid], r=radius, workers=1)
        n_in[valid] = [max(0, len(c) - 1) for c in counts]
    return pd.DataFrame({"knn_d1": knn_d1, "n_neighbors_30um": n_in})

